import{_ as s,o as a,c as n,aw as e}from"./chunks/framework.Dq2onT5h.js";const l=JSON.parse('{"title":"ADR 004: Blockchain Core Data Types","description":"","frontmatter":{"head":[["meta",{"name":"og:title","content":"ADR 004: Blockchain Core Data Types | Evolve"},{"name":"og:description","content":false}]]},"headers":[],"relativePath":"adr/adr-004-core-types.md","filePath":"adr/adr-004-core-types.md","lastUpdated":1760705574000}');const o=s({name:"adr/adr-004-core-types.md"},[["render",function(s,l,o,t,p,c){return a(),n("div",null,[...l[0]||(l[0]=[e('<h1 id="adr-004-blockchain-core-data-types" tabindex="-1">ADR 004: Blockchain Core Data Types <a class="header-anchor" href="#adr-004-blockchain-core-data-types" aria-label="Permalink to &quot;ADR 004: Blockchain Core Data Types&quot;">​</a></h1><h2 id="changelog" tabindex="-1">Changelog <a class="header-anchor" href="#changelog" aria-label="Permalink to &quot;Changelog&quot;">​</a></h2><ul><li>19.04.2021: Initial Draft</li><li>29.09.2022: Rename Optimint to rollmint</li><li>22.01.2023: Rename rollmint to Rollkit</li></ul><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>This document describes the core data structures of any Rollkit-powered blockchain.</p><h2 id="alternative-approaches" tabindex="-1">Alternative Approaches <a class="header-anchor" href="#alternative-approaches" aria-label="Permalink to &quot;Alternative Approaches&quot;">​</a></h2><p>Alternatives for ChainID:</p><ul><li>an integer type like unit64</li><li>a string that fulfills some basic rules like the ChainID for Cosmos chains</li></ul><h2 id="decision" tabindex="-1">Decision <a class="header-anchor" href="#decision" aria-label="Permalink to &quot;Decision&quot;">​</a></h2><p>We design the core data types as minimalistic as possible, i.e. they only contain the absolute necessary data for an optimistic applications to function properly. If there are any additional fields that conflict with above&#39;s claimed minimalism, then they are necessarily inherited by the ABCI imposed separation between application state machine and consensus/networking (often also referred to as ABCI-server and -client). Where such tradeoffs are made, we explicitly comment on them.</p><h2 id="detailed-design" tabindex="-1">Detailed Design <a class="header-anchor" href="#detailed-design" aria-label="Permalink to &quot;Detailed Design&quot;">​</a></h2><h3 id="transactions" tabindex="-1">Transactions <a class="header-anchor" href="#transactions" aria-label="Permalink to &quot;Transactions&quot;">​</a></h3><p>In Rollkit, like in Tendermint, Transactions are just an opaque slice of bytes:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Tx</span><span style="color:#767676;"> []</span><span style="color:#B8A6FF;">byte</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Txs</span><span style="color:#767676;"> []</span><span style="color:#CDA4EB;">Tx</span></span></code></pre></div><p>If necessary <code>Tx</code> could be turned into a struct. Currently, there is no need for that though.</p><h3 id="block-header" tabindex="-1">Block Header <a class="header-anchor" href="#block-header" aria-label="Permalink to &quot;Block Header&quot;">​</a></h3><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> NamespaceID</span><span style="color:#767676;"> [</span><span style="color:#FFECB6;">8</span><span style="color:#767676;">]</span><span style="color:#B8A6FF;">byte</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Header</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Block and App version</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Version </span><span style="color:#CDA4EB;">Version</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // NamespaceID identifies this chain e.g. when connected to other chains via IBC.</span></span>\n<span class="line"><span style="color:#DBD7CA;">    NamespaceID </span><span style="color:#CDA4EB;">NamespaceID</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#DBD7CA;">    Height  </span><span style="color:#B8A6FF;">uint64</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Time    </span><span style="color:#B8A6FF;">uint64</span><span style="color:#A0A0A0;"> // time in tai64 format</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">    // prev block info</span></span>\n<span class="line"><span style="color:#DBD7CA;">    LastHeaderHash </span><span style="color:#767676;">[</span><span style="color:#FFECB6;">32</span><span style="color:#767676;">]</span><span style="color:#B8A6FF;">byte</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">    // hashes of block data</span></span>\n<span class="line"><span style="color:#DBD7CA;">    DataHash           </span><span style="color:#767676;">[</span><span style="color:#FFECB6;">32</span><span style="color:#767676;">]</span><span style="color:#B8A6FF;">byte</span><span style="color:#A0A0A0;"> // Block.Data root aka Transactions</span></span>\n<span class="line"><span style="color:#DBD7CA;">    AppHash            </span><span style="color:#767676;">[</span><span style="color:#FFECB6;">32</span><span style="color:#767676;">]</span><span style="color:#B8A6FF;">byte</span><span style="color:#A0A0A0;">  // state after applying txs from the current block</span></span>\n<span class="line"></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">    // Note that the address can be derived from the pubkey which can be derived</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // from the signature when using secp256k.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // We keep this in case users choose another signature format where the</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // pubkey can&#39;t be recovered by the signature (e.g. ed25519).</span></span>\n<span class="line"><span style="color:#DBD7CA;">    ProposerAddress </span><span style="color:#CDA4EB;">Address</span><span style="color:#A0A0A0;">  // original proposer of the block</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// Version captures the consensus rules for processing a block in the blockchain,</span></span>\n<span class="line"><span style="color:#A0A0A0;">// including all blockchain data structures and the rules of the application&#39;s</span></span>\n<span class="line"><span style="color:#A0A0A0;">// state transition machine.</span></span>\n<span class="line"><span style="color:#A0A0A0;">// This is equivalent to the tmversion.Consensus type in Tendermint.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Version</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Block </span><span style="color:#B8A6FF;">uint32</span></span>\n<span class="line"><span style="color:#DBD7CA;">    App   </span><span style="color:#B8A6FF;">uint32</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><h3 id="block-and-block-data" tabindex="-1">Block and Block.Data <a class="header-anchor" href="#block-and-block-data" aria-label="Permalink to &quot;Block and Block.Data&quot;">​</a></h3><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Block</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Header      </span><span style="color:#CDA4EB;">Header</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Data        </span><span style="color:#CDA4EB;">Data</span></span>\n<span class="line"><span style="color:#DBD7CA;">    LastCommit  </span><span style="color:#888888;">*</span><span style="color:#CDA4EB;">Commit</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Data</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Txs </span><span style="color:#CDA4EB;">Txs</span></span>\n<span class="line"><span style="color:#DBD7CA;">    IntermediateStateRoots </span><span style="color:#CDA4EB;">IntermediateStateRoots</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Evidence </span><span style="color:#CDA4EB;">EvidenceData</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> EvidenceData</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Evidence </span><span style="color:#767676;">[]</span><span style="color:#CDA4EB;">Evidence</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><h4 id="evidence" tabindex="-1">Evidence <a class="header-anchor" href="#evidence" aria-label="Permalink to &quot;Evidence&quot;">​</a></h4><p><code>Evidence</code> represents a go-interface (or oneof in protobuf) of known set of concrete fraud-proofs. The details for this will be defined in a separated adr/PR.</p><p>Here is an incomplete list of potential evidence types:</p><ul><li>Same Aggregator signed two different blocks at the same height <ul><li>figure out if this is actually malicious / slashable behaviour - e.g. clients could simply accept the last block included in a LL block</li></ul></li><li>State Transition Fraud Proofs (for previous blocks)</li></ul><h4 id="commit" tabindex="-1">Commit <a class="header-anchor" href="#commit" aria-label="Permalink to &quot;Commit&quot;">​</a></h4><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> Commit</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Height     </span><span style="color:#B8A6FF;">uint64</span></span>\n<span class="line"><span style="color:#DBD7CA;">    HeaderHash </span><span style="color:#767676;">[</span><span style="color:#FFECB6;">32</span><span style="color:#767676;">]</span><span style="color:#B8A6FF;">byte</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Signatures </span><span style="color:#767676;">[]</span><span style="color:#CDA4EB;">Signature</span><span style="color:#A0A0A0;"> // most of the time this is a single signature</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><h4 id="consensusparams" tabindex="-1">ConsensusParams <a class="header-anchor" href="#consensusparams" aria-label="Permalink to &quot;ConsensusParams&quot;">​</a></h4><p><a href="https://docs.tendermint.com/master/spec/core/state.html#consensusparams" target="_blank" rel="noreferrer">ConsensusParams</a> can be updated by the application through ABCI. This could be seen as a state transition and the ConsensusHash in the header would then require a dedicated state fraud proof. That said, none of the existing default Cosmos-SDK modules actually make use of this functionality though. Hence, we can treat the ConsensusParams as constants (for the same app version). We clearly need to communicate this to optimistic application chain developers. Ideally, we should ensure this programmatically to guarantee that this assumption always holds inside Rollkit.</p><p>The ConsensusParams have the exact same structure as in Tendermint. For the sake of self-containedness we still list them here:</p><div class="language-go"><button title="Copy Code" class="copy"></button><span class="lang">go</span><pre class="shiki ev-dark vp-code" tabindex="0"><code><span class="line"><span style="color:#A0A0A0;">// ConsensusParams contains consensus critical parameters that determine the</span></span>\n<span class="line"><span style="color:#A0A0A0;">// validity of blocks.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> ConsensusParams</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Block     </span><span style="color:#CDA4EB;">BlockParams</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Evidence  </span><span style="color:#CDA4EB;">EvidenceParams</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Validator </span><span style="color:#CDA4EB;">ValidatorParams</span></span>\n<span class="line"><span style="color:#DBD7CA;">    Version   </span><span style="color:#CDA4EB;">VersionParams</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// BlockParams contains limits on the block size.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> BlockParams</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Max block size, in bytes.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Note: must be greater than 0</span></span>\n<span class="line"><span style="color:#DBD7CA;">    MaxBytes </span><span style="color:#B8A6FF;">int64</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Max gas per block.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Note: must be greater or equal to -1</span></span>\n<span class="line"><span style="color:#DBD7CA;">    MaxGas </span><span style="color:#B8A6FF;">int64</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Minimum time increment between consecutive blocks (in milliseconds) If the</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // block header timestamp is ahead of the system clock, decrease this value.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    //</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Not exposed to the application.</span></span>\n<span class="line"><span style="color:#DBD7CA;">    TimeIotaMs </span><span style="color:#B8A6FF;">int64</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// EvidenceParams determine how we handle evidence of malfeasance.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> EvidenceParams</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Max age of evidence, in blocks.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    //</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // The basic formula for calculating this is: MaxAgeDuration / {average block</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // time}.</span></span>\n<span class="line"><span style="color:#DBD7CA;">    MaxAgeNumBlocks </span><span style="color:#B8A6FF;">int64</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Max age of evidence, in time.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    //</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // It should correspond with an app&#39;s &quot;unbonding period&quot; or other similar</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // mechanism for handling [Nothing-At-Stake</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // attacks](https://vitalik.eth.limo/general/2017/12/31/pos_faq.html#what-is-the-nothing-at-stake-problem-and-how-can-it-be-fixed).</span></span>\n<span class="line"><span style="color:#DBD7CA;">    MaxAgeDuration </span><span style="color:#CDA4EB;">time</span><span style="color:#767676;">.</span><span style="color:#CDA4EB;">Duration</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // This sets the maximum size of total evidence in bytes that can be committed in a single block.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // and should fall comfortably under the max block bytes.</span></span>\n<span class="line"><span style="color:#A0A0A0;">    // Default is 1048576 or 1MB</span></span>\n<span class="line"><span style="color:#DBD7CA;">    MaxBytes </span><span style="color:#B8A6FF;">int64</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// ValidatorParams restrict the public key types validators can use.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> ValidatorParams</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    PubKeyTypes </span><span style="color:#767676;">[]</span><span style="color:#B8A6FF;">string</span></span>\n<span class="line"><span style="color:#767676;">}</span></span>\n<span class="line"></span>\n<span class="line"><span style="color:#A0A0A0;">// VersionParams contains the ABCI application version.</span></span>\n<span class="line"><span style="color:#B8A6FF;">type</span><span style="color:#CDA4EB;"> VersionParams</span><span style="color:#B8A6FF;"> struct</span><span style="color:#767676;"> {</span></span>\n<span class="line"><span style="color:#DBD7CA;">    AppVersion </span><span style="color:#B8A6FF;">uint64</span></span>\n<span class="line"><span style="color:#767676;">}</span></span></code></pre></div><h2 id="status" tabindex="-1">Status <a class="header-anchor" href="#status" aria-label="Permalink to &quot;Status&quot;">​</a></h2><p>Proposed and partly implemented.</p><p>For finishing the implementation these items need to be tackled at least:</p><ul><li>[ ] methods on core types (e.g. for hashing and basic validation etc)</li><li>[ ] equivalent types for serialization purposes (probably protobuf)</li><li>[ ] conversion from and to protobuf</li></ul><h2 id="consequences" tabindex="-1">Consequences <a class="header-anchor" href="#consequences" aria-label="Permalink to &quot;Consequences&quot;">​</a></h2><h3 id="positive" tabindex="-1">Positive <a class="header-anchor" href="#positive" aria-label="Permalink to &quot;Positive&quot;">​</a></h3><ul><li>very close to the original Tendermint types which makes on-boarding devs familiar for the Cosmos-SDK and Tendermint easier</li></ul><h3 id="negative" tabindex="-1">Negative <a class="header-anchor" href="#negative" aria-label="Permalink to &quot;Negative&quot;">​</a></h3><ul><li>dependency on abci types for evidence interface (in the current implementation at least)</li></ul><h3 id="neutral" tabindex="-1">Neutral <a class="header-anchor" href="#neutral" aria-label="Permalink to &quot;Neutral&quot;">​</a></h3><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><ul><li><a href="https://github.com/evstack/ev-node/pull/41" target="_blank" rel="noreferrer">https://github.com/evstack/ev-node/pull/41</a></li></ul>',41)])])}]]);export{l as __pageData,o as default};
